proposedSchema.zod:
import { z, defineCollection } from 'astro:content';

const post = defineCollection({
  type: 'content', // MDX files in src/content/post/
  schema: ({ image }) => z.object({
    title: z.string(),
    slug: z.string(), // preserve original WP slug for redirects
    publishDate: z.coerce.date(), // from post.date
    updatedDate: z.coerce.date().optional(), // from post.modified when it differs from publishDate
    author: z.enum(['Juma', 'Ren', 'Lucia', 'Byron McGovern']).default('Juma'),
    categories: z.array(z.string()).default([]), // human-readable names; drop bare 'Uncategorized'
    tags: z.array(z.string()).default([]), // sparse; 180/196 empty
    heroImage: image().optional(), // resolved from featured_media -> manifest -> local file, else yoast og_image
    heroImageAlt: z.string().optional(), // from media-manifest .alt
    excerpt: z.string().optional(), // from excerpt.rendered, entity-decoded & detagged
    draft: z.boolean().default(false), // all source posts are status 'publish' -> false
    legacyId: z.number().optional(), // original WP post id, for redirect/traceability
  }),
});

export const collections = { post };
